import java.io.IOException;
import java.io.PrintWriter;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

public class SecureServlet extends HttpServlet {

    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");

        // Sanitize user input to prevent XSS
        String sanitizedInput = sanitizeInput(userInput);

        String output = "<p>User input: " + sanitizedInput + "</p>";

        PrintWriter out = response.getWriter();
        out.println(output);
    }

    private String sanitizeInput(String input) {
        // Implement proper input sanitization based on your requirements
        // For example, you can use OWASP Java Encoder or HTML escaping functions

        // Here is a simple example using Apache Commons Text library to escape HTML characters
        return org.apache.commons.text.StringEscapeUtils.escapeHtml4(input);
    }
}

